/// <summary>
/// Resolves and validates a public invite-link token in a single round-trip.
/// </summary>
/// <remarks>
/// Returning a tuple rather than throwing keeps the validation logic re-usable
/// across queries (where 410 is expected) and commands (where the same handler
/// may translate the failure differently). Callers throw
/// <see cref="EventSync.Api.Common.Exceptions.InvalidInviteException"/> when they
/// want to surface a "Gone" response.
/// </remarks>
public interface IInviteValidationService
{
    /// <summary>
    /// Looks up the invite link by token and reports the first reason it cannot be honoured.
    /// </summary>
    /// <param name="token">URL-safe random token.</param>
    /// <param name="forSubmission">
    /// When <c>true</c>, additionally rejects links whose underlying event has been
    /// cancelled. When <c>false</c> (the default, used by GET) cancelled events are
    /// returned so the public page can render a "cancelled" notice.
    /// </param>
    /// <param name="cancellationToken">Cancellation token.</param>
    /// <returns>
    /// A tuple of <c>(Link, ErrorMessage)</c>. <c>Link</c> is non-null only when validation
    /// succeeds; <c>ErrorMessage</c> is non-null only when validation fails.
    /// </returns>
    Task<(InviteLink? Link, string? ErrorMessage)> ValidateTokenAsync(
