/// <inheritdoc cref="IInviteValidationService"/>
public sealed class InviteValidationService : IInviteValidationService
{
    private readonly AppDbContext _dbContext;

    /// <summary>Initializes a new instance of <see cref="InviteValidationService"/>.</summary>
    public InviteValidationService(AppDbContext dbContext)
    {
        _dbContext = dbContext;
    }

    /// <inheritdoc/>
    public async Task<(InviteLink? Link, string? ErrorMessage)> ValidateTokenAsync(
        string token,
        bool forSubmission = false,
        CancellationToken cancellationToken = default)
    {
        if (string.IsNullOrWhiteSpace(token))
        {
            return (null, "Invite link not found");
        }

        // IgnoreQueryFilters so a soft-deleted Event still surfaces the link, allowing us
        // to return a precise "Event no longer available" message rather than the generic
        // "not found" (which would otherwise leak whether the token had ever existed).
        var link = await _dbContext.InviteLinks
            .IgnoreQueryFilters()
            .Include(l => l.Event)
                .ThenInclude(e => e.EventType)
            .Include(l => l.Event)
                .ThenInclude(e => e.Organizer)
            .AsNoTracking()
            .FirstOrDefaultAsync(l => l.Token == token, cancellationToken);

        if (link is null)
        {
            return (null, "Invite link not found");
        }

        if (!link.IsActive)
        {
            return (null, "This invite link has been deactivated");
        }

        if (link.ExpiresAt is DateTime expiry && expiry < DateTime.Now)
        {
            return (null, "This invite link has expired");
        }

        if (link.MaxUses is int max && link.UseCount >= max)
        {
            return (null, "This invite link has reached its limit");
        }

        if (link.Event.IsDeleted)
        {
            return (null, "Event no longer available");
        }

        // Cancelled events are still readable (so the public page can show a notice),
        // but new RSVP submissions are blocked.
        if (forSubmission && link.Event.IsCancelled)
        {
            return (null, "This event has been cancelled and is no longer accepting RSVPs");
        }

        return (link, null);
    }
